module protobuf

include("descriptor_pb.jl")
include("compiler/compiler.jl")

# Well-known types — generated by ProtocGen' own codegen via
# gen/regen_wkt.jl. Include order follows the proto import graph: each
# file's dependencies must already be evaluated when its struct field
# type annotations are parsed (otherwise a bare `Any` in `type_pb.jl`
# would fall through to `Base.Any`). `struct.proto` is still deferred —
# it needs recursion support for the `Value ↔ ListValue ↔ Struct` cycle.
include("any_pb.jl")
include("duration_pb.jl")
include("empty_pb.jl")
include("field_mask_pb.jl")
include("source_context_pb.jl")
include("timestamp_pb.jl")
include("wrappers_pb.jl")
include("type_pb.jl")        # imports any, source_context
include("api_pb.jl")         # imports source_context, type
include("struct_pb.jl")      # internal Struct↔Value↔ListValue cycle

end # module protobuf
